if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf();$action=(string)($_POST['action']??'');try{if($action==='general'){$baseUrl=rtrim(trim((string)$_POST['base_url']),'/');if($baseUrl!==''&&!filter_var($baseUrl,FILTER_VALIDATE_URL))throw new RuntimeException('Некорректный URL.');$accent=(string)($_POST['accent_color']??'#5b5ce2');if(!preg_match('/^#[0-9a-fA-F]{6}$/',$accent))$accent='#5b5ce2';$oldLogo=setting('logo_path','');$logo=isset($_POST['remove_logo'])?null:safe_brand_logo_upload($_FILES['logo']??[],$oldLogo?:null);if(isset($_POST['remove_logo'])&&$oldLogo){@unlink(dirname(__DIR__).'/'.ltrim($oldLogo,'/'));}save_setting('logo_path',$logo??'');save_setting('accent_color',$accent);save_setting('school_name',trim((string)$_POST['school_name'])?:APP_NAME);save_setting('base_url',$baseUrl);save_setting('default_language',in_array($_POST['default_language']??'ru',['ru','en'],true)?$_POST['default_language']:'ru');save_setting('allow_public_archive',isset($_POST['allow_public_archive'])?'1':'0');save_setting('terminal_redirect_seconds',(string)max(3,min(60,(int)$_POST['terminal_redirect_seconds'])));audit_log('general_settings_updated','settings');flash('success','Общие настройки сохранены.');}elseif($action==='security'){save_setting('session_timeout_minutes',(string)max(5,min(480,(int)$_POST['session_timeout_minutes'])));save_setting('max_login_attempts',(string)max(3,min(20,(int)$_POST['max_login_attempts'])));save_setting('lockout_minutes',(string)max(1,min(1440,(int)$_POST['lockout_minutes'])));audit_log('security_settings_updated','settings');flash('success','Параметры безопасности сохранены.');}elseif($action==='password'){$current=(string)$_POST['current_password'];$new=(string)$_POST['new_password'];$st=db()->prepare('SELECT password_hash FROM admins WHERE id=?');$st->execute([(int)$admin['id']]);if(!password_verify($current,(string)$st->fetchColumn()))throw new RuntimeException('Текущий пароль неверен.');if(strlen($new)<10)throw new RuntimeException('Новый пароль — минимум 10 символов.');db()->prepare('UPDATE admins SET password_hash=? WHERE id=?')->execute([password_hash($new,PASSWORD_DEFAULT),(int)$admin['id']]);audit_log('own_password_changed','admin',(int)$admin['id']);flash('success','Пароль изменён.');}elseif($action==='reset_election'){$id=(int)$_POST['election_id'];if(trim((string)$_POST['confirmation'])!=='УДАЛИТЬ ГОЛОСА')throw new RuntimeException('Введите точную фразу подтверждения.');$e=election_by_id($id);if(!$e)throw new RuntimeException('Выборы не найдены.');if($e['status']==='open')throw new RuntimeException('Сначала закройте голосование.');backup_database('before-reset-'.$id);$pdo=db();$pdo->beginTransaction();$pdo->prepare('DELETE FROM votes WHERE election_id=?')->execute([$id]);$pdo->prepare('DELETE FROM participation WHERE election_id=?')->execute([$id]);$pdo->commit();audit_log('election_votes_reset','election',$id);flash('success','Голоса и отметки участия удалены. Создана резервная копия.');}elseif($action==='integrity'){$result=db()->query('PRAGMA integrity_check')->fetchAll(PDO::FETCH_COLUMN);$ok=$result===['ok'];audit_log('database_integrity_check','database',null,['result'=>$result]);flash($ok?'success':'error',$ok?'Проверка целостности: база исправна.':'SQLite сообщил: '.implode('; ',$result));}elseif($action==='backup'){ $path=backup_database('manual');audit_log('backup_created','backup',null,['file'=>basename($path)]);flash('success','Резервная копия создана.');}}catch(Throwable $e){if(isset($pdo)&&$pdo->inTransaction())$pdo->rollBack();flash('error',database_error_message($e));}redirect('settings.php');}
$backups=[];foreach(glob(BACKUP_ROOT.'/*.sqlite')?:[] as $file)$backups[]=['name'=>basename($file),'size'=>filesize($file),'time'=>filemtime($file)];usort($backups,static fn($a,$b)=>$b['time']<=>$a['time']);$elections=db()->query('SELECT id,title,status FROM elections ORDER BY id DESC')->fetchAll();
$pageTitle='Настройки';$isAdminArea=true;require dirname(__DIR__).'/partials/header.php';
